+@preconcurrency import ApplicationServices
+import Foundation
+
+typealias HotkeyEffectHandler = @MainActor @Sendable (HotkeyEffect) -> Void
+
+protocol HotkeyMonitoring: AnyObject {
+    var isRunning: Bool { get }
+    func start(bindings: HotkeyBindings, effectHandler: @escaping HotkeyEffectHandler) throws
+    func stop()
+}
+
+protocol AccessibilityPermissionChecking {
+    func isTrusted(prompt: Bool) -> Bool
+}
+
+struct AccessibilityPermissionChecker: AccessibilityPermissionChecking {
+    func isTrusted(prompt: Bool) -> Bool {
+        let options = [
+            kAXTrustedCheckOptionPrompt.takeUnretainedValue() as String: prompt
+        ] as CFDictionary
+        return AXIsProcessTrustedWithOptions(options)
+    }
+}
+
+enum HotkeyMonitorError: LocalizedError {
+    case accessibilityDenied
+    case eventTapUnavailable
+
+    var errorDescription: String? {
+        switch self {
+        case .accessibilityDenied:
+            return "Accessibility permission is required for hotkey monitoring."
+        case .eventTapUnavailable:
+            return "The hotkey monitor could not be started."
+        }
+    }
+}
+
+final class GlobalHotkeyMonitor: HotkeyMonitoring, @unchecked Sendable {
+    private let accessibilityChecker: any AccessibilityPermissionChecking
+
+    private(set) var isRunning = false
+
+    private var thread: Thread?
+    private var tap: CFMachPort?
+    private var runLoop: CFRunLoop?
+    private var runLoopSource: CFRunLoopSource?
+    private var keepAlivePort: Port?
+    private var receiver: HotkeyEventReceiver?
+
+    init(accessibilityChecker: any AccessibilityPermissionChecking = AccessibilityPermissionChecker()) {
+        self.accessibilityChecker = accessibilityChecker
+    }
+
+    func start(bindings: HotkeyBindings, effectHandler: @escaping HotkeyEffectHandler) throws {
+        if isRunning {
+            return
+        }
+
+        let isTrusted = accessibilityChecker.isTrusted(prompt: false) || accessibilityChecker.isTrusted(prompt: true)
+        guard isTrusted else {
+            throw HotkeyMonitorError.accessibilityDenied
+        }
+
+        let readySemaphore = DispatchSemaphore(value: 0)
+        let startupState = HotkeyMonitorStartupState()
+        let dispatchEffect: @Sendable (HotkeyEffect) -> Void = { effect in
+            Task { @MainActor in
+                effectHandler(effect)
+            }
+        }
+
+        let thread = Thread { [weak self] in
+            guard let self else {
+                startupState.setError(HotkeyMonitorError.eventTapUnavailable)
+                readySemaphore.signal()
+                return
+            }
+
+            autoreleasepool {
+                let receiver = HotkeyEventReceiver(bindings: bindings, effectHandler: dispatchEffect)
+                let callback: CGEventTapCallBack = { _, type, event, userInfo in
+                    guard let userInfo else {
+                        return Unmanaged.passUnretained(event)
+                    }
+
+                    let receiver = Unmanaged<HotkeyEventReceiver>.fromOpaque(userInfo).takeUnretainedValue()
+                    receiver.handle(event: event, type: type)
+                    return Unmanaged.passUnretained(event)
+                }
+
+                guard let tap = CGEvent.tapCreate(
+                    tap: .cgSessionEventTap,
+                    place: .tailAppendEventTap,
+                    options: .listenOnly,
+                    eventsOfInterest: GlobalHotkeyMonitor.eventMask,
+                    callback: callback,
+                    userInfo: UnsafeMutableRawPointer(Unmanaged.passUnretained(receiver).toOpaque())
+                ) else {
+                    startupState.setError(HotkeyMonitorError.eventTapUnavailable)
+                    readySemaphore.signal()
+                    return
+                }
+
+                let source = CFMachPortCreateRunLoopSource(kCFAllocatorDefault, tap, 0)
+                let runLoop = CFRunLoopGetCurrent()
+                let keepAlivePort = Port()
+
+                self.receiver = receiver
+                self.tap = tap
+                self.runLoopSource = source
+                self.runLoop = runLoop
+                self.keepAlivePort = keepAlivePort
+
+                CFRunLoopAddSource(runLoop, source, .commonModes)
+                CGEvent.tapEnable(tap: tap, enable: true)
+                RunLoop.current.add(keepAlivePort, forMode: .default)
+
+                readySemaphore.signal()
+                CFRunLoopRun()
+            }
+        }
+
+        thread.name = "GhostPepperHotkeyMonitor"
+        thread.qualityOfService = .userInitiated
+        self.thread = thread
+        thread.start()
+        readySemaphore.wait()
+
+        if let error = startupState.error {
+            self.thread = nil
+            throw error
+        }
+
+        isRunning = true
+    }
+
+    func stop() {
+        guard isRunning else {
+            return
+        }
+
+        if let tap {
+            CGEvent.tapEnable(tap: tap, enable: false)
+        }
+
+        if let runLoop {
+            CFRunLoopPerformBlock(runLoop, CFRunLoopMode.commonModes.rawValue) {
+                CFRunLoopStop(runLoop)
+            }
+            CFRunLoopWakeUp(runLoop)
+        }
+
+        isRunning = false
+        keepAlivePort = nil
+        runLoopSource = nil
+        runLoop = nil
+        tap = nil
+        receiver = nil
+        thread = nil
+    }
+
+    private static let eventMask: CGEventMask = eventMask(for: .flagsChanged)
+        | eventMask(for: .keyDown)
+        | eventMask(for: .keyUp)
+
+    private static func eventMask(for type: CGEventType) -> CGEventMask {
+        CGEventMask(1) << CGEventMask(type.rawValue)
+    }
+}
+
+private final class HotkeyEventReceiver {
+    private let engine: HotkeyEngine
+    private let effectHandler: @Sendable (HotkeyEffect) -> Void
+
+    init(bindings: HotkeyBindings, effectHandler: @escaping @Sendable (HotkeyEffect) -> Void) {
+        engine = HotkeyEngine(bindings: bindings)
+        self.effectHandler = effectHandler
+    }
+
+    func handle(event: CGEvent, type: CGEventType) {
+        guard let snapshot = snapshot(for: event, type: type) else {
+            return
+        }
+
+        for effect in engine.process(snapshot) {
+            effectHandler(effect)
+        }
+    }
+
+    private func snapshot(for event: CGEvent, type: CGEventType) -> HotkeyEventSnapshot? {
+        guard let key = HotkeyKey(rawValue: UInt16(event.getIntegerValueField(.keyboardEventKeycode))) else {
+            return nil
+        }
+
+        switch type {
+        case .flagsChanged:
+            return .flagsChanged(key)
+        case .keyDown:
+            return .keyDown(key)
+        case .keyUp:
+            return .keyUp(key)
+        default:
+            return nil
+        }
+    }
+}
+
+private final class HotkeyMonitorStartupState: @unchecked Sendable {
+    private let lock = NSLock()
+    private var _error: Error?
+
+    var error: Error? {
+        lock.lock()
+        let value = _error
+        lock.unlock()
+        return value
+    }
+
+    func setError(_ error: Error) {
+        lock.lock()
+        _error = error
+        lock.unlock()
+    }
+}

